import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, fireEvent, waitFor } from '@testing-library/svelte';
import TimeTravelSimulator from './TimeTravelSimulator.svelte';
import type { CompiledExperiment } from '$lib/types/experiment';

// Mock the headless runner
vi.mock('@psyforge/headless', () => ({
  HeadlessRunner: vi.fn().mockImplementation(() => ({
    simulate: vi.fn().mockResolvedValue({
      totalDuration: 10000,
      participantResults: [],
      performanceMetrics: {
        simulationTime: 100,
        wallClockTime: 1000,
        speedMultiplier: 100
      }
    }),
    simulateUntil: vi.fn().mockResolvedValue({
      currentTime: 0,
      phase: 'stimulus',
      activeStimuli: [{ type: 'text', content: 'Test', color: '#000' }],
      events: [],
      participantId: 'P001',
      trialNumber: 1,
      totalTrials: 10,
      blockNumber: 1,
      totalBlocks: 1,
      condition: 'test'
    }),
    getMemoryUsage: vi.fn().mockReturnValue({
      heapUsedMB: 50,
      heapTotalMB: 100,
      gcPauses: 0
    })
  })),
  CognitiveModelsFactory: {
    create: vi.fn().mockReturnValue({
      reactionTime: vi.fn(),
      accuracy: vi.fn()
    })
  }
}));

const mockExperiment: CompiledExperiment = {
  id: 'test-exp',
  name: 'Test Experiment',
  description: 'Test description',
  version: '1.0.0',
  timeline: {
    id: 'timeline-1',
    type: 'sequential',
    children: []
  }
};

describe('TimeTravelSimulator', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('renders loading state initially', async () => {
    const { getByText } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    expect(getByText('Initializing simulator...')).toBeInTheDocument();
  });

  it('renders empty state when no experiment', () => {
    const { getByText } = render(TimeTravelSimulator, {
      props: { experiment: null }
    });

    expect(getByText('No experiment loaded')).toBeInTheDocument();
  });

  it('initializes runner and shows controls', async () => {
    const { getByLabelText, getByText } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    await waitFor(() => {
      expect(getByLabelText('Experiment timeline')).toBeInTheDocument();
      expect(getByLabelText('Play')).toBeInTheDocument();
      expect(getByLabelText('Stop')).toBeInTheDocument();
      expect(getByLabelText('Playback speed')).toBeInTheDocument();
    });
  });

  it('plays and pauses simulation', async () => {
    const { getByLabelText } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    await waitFor(() => {
      const playButton = getByLabelText('Play');
      expect(playButton).toBeInTheDocument();
    });

    const playButton = getByLabelText('Play');
    await fireEvent.click(playButton);

    await waitFor(() => {
      expect(getByLabelText('Pause')).toBeInTheDocument();
    });

    const pauseButton = getByLabelText('Pause');
    await fireEvent.click(pauseButton);

    expect(getByLabelText('Play')).toBeInTheDocument();
  });

  it('seeks to specific time', async () => {
    const { getByLabelText } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    await waitFor(() => {
      expect(getByLabelText('Experiment timeline')).toBeInTheDocument();
    });

    const slider = getByLabelText('Experiment timeline') as HTMLInputElement;
    await fireEvent.input(slider, { target: { value: '5000' } });

    expect(slider.value).toBe('5000');
  });

  it('changes playback speed', async () => {
    const { getByLabelText } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    await waitFor(() => {
      expect(getByLabelText('Playback speed')).toBeInTheDocument();
    });

    const speedSelect = getByLabelText('Playback speed') as HTMLSelectElement;
    await fireEvent.change(speedSelect, { target: { value: '2' } });

    expect(speedSelect.value).toBe('2');
  });

  it('handles keyboard shortcuts', async () => {
    const { getByLabelText } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    await waitFor(() => {
      expect(getByLabelText('Play')).toBeInTheDocument();
    });

    // Space to play
    await fireEvent.keyDown(window, { key: ' ' });
    expect(getByLabelText('Pause')).toBeInTheDocument();

    // Space to pause
    await fireEvent.keyDown(window, { key: ' ' });
    expect(getByLabelText('Play')).toBeInTheDocument();

    // Arrow keys to seek
    const slider = getByLabelText('Experiment timeline') as HTMLInputElement;
    const initialValue = parseFloat(slider.value);

    await fireEvent.keyDown(window, { key: 'ArrowRight' });
    expect(parseFloat(slider.value)).toBeGreaterThan(initialValue);
  });

  it('displays performance metrics', async () => {
    const { getByText } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    await waitFor(() => {
      expect(getByText('FPS:')).toBeInTheDocument();
      expect(getByText('Memory:')).toBeInTheDocument();
      expect(getByText('50.0MB')).toBeInTheDocument();
    });
  });

  it('handles errors gracefully', async () => {
    const HeadlessRunner = (await import('@psyforge/headless')).HeadlessRunner as any;
    HeadlessRunner.mockImplementationOnce(() => ({
      simulate: vi.fn().mockRejectedValue(new Error('Simulation failed'))
    }));

    const { getByText } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    await waitFor(() => {
      expect(getByText('Failed to initialize simulator')).toBeInTheDocument();
      expect(getByText('Retry')).toBeInTheDocument();
    });
  });

  it('dispatches events on time change', async () => {
    const handleTimeChange = vi.fn();

    const { getByLabelText, component } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    component.$on('timechange', handleTimeChange);

    await waitFor(() => {
      expect(getByLabelText('Experiment timeline')).toBeInTheDocument();
    });

    const slider = getByLabelText('Experiment timeline') as HTMLInputElement;
    await fireEvent.input(slider, { target: { value: '5000' } });

    expect(handleTimeChange).toHaveBeenCalled();
  });

  it('stops at end of simulation', async () => {
    const handleEnded = vi.fn();

    const { getByLabelText, component } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    component.$on('ended', handleEnded);

    await waitFor(() => {
      expect(getByLabelText('Play')).toBeInTheDocument();
    });

    // Simulate reaching end by seeking to total duration
    const slider = getByLabelText('Experiment timeline') as HTMLInputElement;
    await fireEvent.input(slider, { target: { value: '10000' } });

    const playButton = getByLabelText('Play');
    await fireEvent.click(playButton);

    // Animation frame would normally trigger ended event
    // For testing, we'll check that play button returns
    await waitFor(() => {
      expect(getByLabelText('Play')).toBeInTheDocument();
    });
  });
});

