      expect(getByLabelText('Playback speed')).toBeInTheDocument();
    });
  });

  it('plays and pauses simulation', async () => {
    const { getByLabelText } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    await waitFor(() => {
      const playButton = getByLabelText('Play');
      expect(playButton).toBeInTheDocument();
    });

