    await fireEvent.click(playButton);

    await waitFor(() => {
      expect(getByLabelText('Pause')).toBeInTheDocument();
    });

    const pauseButton = getByLabelText('Pause');
    await fireEvent.click(pauseButton);

    expect(getByLabelText('Play')).toBeInTheDocument();
  });

  it('seeks to specific time', async () => {
    const { getByLabelText } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    await waitFor(() => {
      expect(getByLabelText('Experiment timeline')).toBeInTheDocument();
    });

    const slider = getByLabelText('Experiment timeline') as HTMLInputElement;
    await fireEvent.input(slider, { target: { value: '5000' } });

    expect(slider.value).toBe('5000');
  });

  it('changes playback speed', async () => {
    const { getByLabelText } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    await waitFor(() => {
      expect(getByLabelText('Playback speed')).toBeInTheDocument();
    });

    const speedSelect = getByLabelText('Playback speed') as HTMLSelectElement;
    await fireEvent.change(speedSelect, { target: { value: '2' } });

    expect(speedSelect.value).toBe('2');
  });

  it('handles keyboard shortcuts', async () => {
    const { getByLabelText } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

