    const handleTimeChange = vi.fn();

    const { getByLabelText, component } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    component.$on('timechange', handleTimeChange);

    await waitFor(() => {
      expect(getByLabelText('Experiment timeline')).toBeInTheDocument();
    });

    const slider = getByLabelText('Experiment timeline') as HTMLInputElement;
    await fireEvent.input(slider, { target: { value: '5000' } });

    expect(handleTimeChange).toHaveBeenCalled();
  });

  it('stops at end of simulation', async () => {
    const handleEnded = vi.fn();

    const { getByLabelText, component } = render(TimeTravelSimulator, {
      props: { experiment: mockExperiment }
    });

    component.$on('ended', handleEnded);

    await waitFor(() => {
      expect(getByLabelText('Play')).toBeInTheDocument();
    });

    // Simulate reaching end by seeking to total duration
    const slider = getByLabelText('Experiment timeline') as HTMLInputElement;
    await fireEvent.input(slider, { target: { value: '10000' } });

    const playButton = getByLabelText('Play');
    await fireEvent.click(playButton);

    // Animation frame would normally trigger ended event
    // For testing, we'll check that play button returns
    await waitFor(() => {
      expect(getByLabelText('Play')).toBeInTheDocument();
    });
  });
});

