  /**
   * Simulate EEG data for neuroscience experiments
   */
  simulateEEGData(timestamp: number): any {
    const eeg = this.virtualDevices.get('eeg') as VirtualEEGDevice | undefined;
    if (!eeg) return null;

    return eeg.simulateEEGSignal(timestamp);
  }

  /**
   * Get current experiment phase
   */
  private getCurrentPhase(): 'stimulus' | 'response' | 'feedback' | 'iti' | 'instruction' {
    // Simple phase detection based on virtual time
    const cycleTime = this.virtualTime % 3; // 3 second trial cycle

    if (cycleTime < 1) return 'stimulus';
    if (cycleTime < 2) return 'response';
    if (cycleTime < 2.5) return 'feedback';
    return 'iti';
  }

  /**
   * Get simulation events for timeline
   */
  private getSimulationEvents(): Array<{ type: string; time: number; description: string }> {
    const events: Array<{ type: string; time: number; description: string }> = [];

    // Generate events based on trial structure
    const trialDuration = 3000; // 3s per trial
    const totalTrials = this.calculateTotalTrials();

    for (let i = 0; i < totalTrials; i++) {
      const trialStart = i * trialDuration;
      events.push({
        type: 'stimulus',
        time: trialStart,
        description: `Trial ${i + 1} stimulus onset`
      });
      events.push({
        type: 'response',
        time: trialStart + 1500,
        description: `Trial ${i + 1} response window`
      });
    }

    return events;
  }

  /**
   * Get current event
   */
  private getCurrentEvent(): { type: string; time: number; description: string } | undefined {
    const events = this.getSimulationEvents();
    const currentTime = this.virtualTime * 1000;

    // Find the most recent event
    for (let i = events.length - 1; i >= 0; i--) {
      if (events[i].time <= currentTime) {
        return events[i];
      }
    }

    return undefined;
  }

  /**
   * Calculate total number of trials
   */
  private calculateTotalTrials(): number {
    // Default to 80 trials if not specified
    return 80;
  }

  /**
   * Get current experimental condition
   */
  private getCurrentCondition(): string {
    // Alternate between conditions for demo
    const trialNumber = Math.floor(this.virtualTime / 3); // 3s per trial
    return trialNumber % 2 === 0 ? 'congruent' : 'incongruent';
  }

  /**
   * Get current instruction text
   */
  private getCurrentInstruction(): string | undefined {
    if (this.virtualTime < 5) {
      return 'Press the key corresponding to the color of the word';
    }
    return undefined;
  }

  /**
   * Get last participant response
   */
  private getLastResponse(): any {
    const participantResults = this.results.get('P001');
    if (!participantResults || participantResults.length === 0) {
      return undefined;
    }

    const lastTrial = participantResults[participantResults.length - 1];
    return {
      key: lastTrial.response.key,
      rt: lastTrial.rt,
      accuracy: lastTrial.correct
    };
  }
}

