import { describe, it, expect, beforeEach } from 'vitest';
import { HeadlessRunner } from '../src/HeadlessRunner';
import { CognitiveModelsFactory } from '../src/CognitiveModels';
import type { CompiledExperiment } from '@psyforge/forgescript';
import type { HeadlessConfig } from '../src/types';

const mockExperiment: CompiledExperiment = {
  id: 'test-exp',
  name: 'Test Experiment',
  description: 'Test with virtual devices',
  version: '1.0.0',
  timeline: {
    id: 'timeline-1',
    type: 'sequential',
    children: []
  }
};

describe('Virtual Device Integration', () => {
  let runner: HeadlessRunner;
  let config: HeadlessConfig;

  beforeEach(() => {
    config = {
      experiment: mockExperiment,
      cognitiveModel: CognitiveModelsFactory.create('simpleRT'),
      participants: 1,
      speedMultiplier: 100,
      randomSeed: 42,
      virtualDevices: {
        keyboard: true,
        keyboardConfig: {
          latency: 10,
          keyPressVariability: 5
        },
        mouse: true,
        mouseConfig: {
          latency: 8,
          movementNoise: 0.1
        },
        eyeTracker: true,
        eyeTrackerConfig: {
          samplingRate: 1000,
          precision: 0.5
        },
        eeg: true,
        eegConfig: {
          samplingRate: 256,
          channels: ['Fz', 'Cz', 'Pz']
        }
      }
    };

    runner = new HeadlessRunner(config);
  });

  it('should initialize all virtual devices', () => {
