import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, fireEvent, waitFor } from '@testing-library/svelte';
import AICommandPalette from './AICommandPalette.svelte';
import type { CompiledExperiment } from '$lib/types/experiment';

// Mock the AI assistant
vi.mock('@psyforge/ai-assistant', () => ({
  AIDesignAssistant: vi.fn().mockImplementation(() => ({
    parseCommand: vi.fn().mockResolvedValue({
      intent: 'add_trial',
      parameters: { type: 'stroop', count: 20 }
    }),
    generateCode: vi.fn().mockResolvedValue(
      `experiment.addTrial({
  type: 'stroop',
  stimulus: { word: 'RED', color: 'blue' },
  duration: 2000
});`
    ),
    validateCode: vi.fn().mockResolvedValue({
      valid: true,
      errors: [],
      warnings: []
    }),
    getAutocompleteSuggestions: vi.fn().mockResolvedValue([
      'Add 20 Stroop trials',
      'Add practice block',
      'Add instruction screen'
    ])
  }))
}));

const mockExperiment: CompiledExperiment = {
  id: 'test-exp',
  name: 'Test Experiment',
  description: 'Test',
  version: '1.0.0',
  timeline: {
    id: 'timeline-1',
    type: 'sequential',
    children: []
  }
};

describe('AICommandPalette', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('renders closed by default', () => {
    const { container } = render(AICommandPalette, {
      props: { isOpen: false }
    });

    expect(container.querySelector('.command-palette')).not.toBeInTheDocument();
  });

  it('renders open when isOpen is true', () => {
    const { getByPlaceholderText } = render(AICommandPalette, {
      props: { isOpen: true, apiKey: 'test-key' }
    });

    expect(getByPlaceholderText('Describe what you want to add to your experiment...')).toBeInTheDocument();
  });

  it('shows API key required modal when no API key', () => {
    const { getByText } = render(AICommandPalette, {
      props: { isOpen: true }
    });

    expect(getByText('API Key Required')).toBeInTheDocument();
  });

  it('focuses input when opened', async () => {
    const { getByPlaceholderText } = render(AICommandPalette, {
      props: { isOpen: true, apiKey: 'test-key' }
    });

    const input = getByPlaceholderText('Describe what you want to add to your experiment...');
    await waitFor(() => {
      expect(document.activeElement).toBe(input);
    });
  });

  it('shows suggestions while typing', async () => {
    const { getByPlaceholderText, getByText } = render(AICommandPalette, {
      props: { isOpen: true, apiKey: 'test-key', experiment: mockExperiment }
    });

    const input = getByPlaceholderText('Describe what you want to add to your experiment...');
    await fireEvent.input(input, { target: { value: 'Add' } });

    await waitFor(() => {
      expect(getByText('Add 20 Stroop trials')).toBeInTheDocument();
      expect(getByText('Add practice block')).toBeInTheDocument();
    });
  });

  it('generates code on submit', async () => {
    const { getByPlaceholderText, getByText } = render(AICommandPalette, {
      props: { isOpen: true, apiKey: 'test-key', experiment: mockExperiment }
    });

    const input = getByPlaceholderText('Describe what you want to add to your experiment...');
    await fireEvent.input(input, { target: { value: 'Add 20 Stroop trials' } });
    await fireEvent.keyDown(input, { key: 'Enter', shiftKey: true });

    await waitFor(() => {
      expect(getByText('Generated Code Preview')).toBeInTheDocument();
      expect(getByText(/experiment\.addTrial/)).toBeInTheDocument();
    });
  });

  it('applies code when Apply button clicked', async () => {
    const handleApply = vi.fn();

    const { getByPlaceholderText, getByText, component } = render(AICommandPalette, {
      props: { isOpen: true, apiKey: 'test-key', experiment: mockExperiment }
    });

    component.$on('apply', handleApply);

    const input = getByPlaceholderText('Describe what you want to add to your experiment...');
    await fireEvent.input(input, { target: { value: 'Add trials' } });
    await fireEvent.keyDown(input, { key: 'Enter', shiftKey: true });

    await waitFor(() => {
      expect(getByText('Apply Code')).toBeInTheDocument();
    });

    await fireEvent.click(getByText('Apply Code'));

    expect(handleApply).toHaveBeenCalledWith(
      expect.objectContaining({
        detail: expect.objectContaining({
          code: expect.stringContaining('experiment.addTrial')
        })
      })
    );
  });

  it('closes on Escape key', async () => {
    const handleClose = vi.fn();

    const { getByPlaceholderText, component } = render(AICommandPalette, {
      props: { isOpen: true, apiKey: 'test-key' }
    });

    component.$on('close', handleClose);

    const input = getByPlaceholderText('Describe what you want to add to your experiment...');
    await fireEvent.keyDown(input, { key: 'Escape' });

    expect(handleClose).toHaveBeenCalled();
  });

  it('navigates suggestions with arrow keys', async () => {
    const { getByPlaceholderText, container } = render(AICommandPalette, {
      props: { isOpen: true, apiKey: 'test-key', experiment: mockExperiment }
    });

    const input = getByPlaceholderText('Describe what you want to add to your experiment...');
    await fireEvent.input(input, { target: { value: 'Add' } });

    await waitFor(() => {
      const suggestions = container.querySelectorAll('.suggestion');
      expect(suggestions).toHaveLength(3);
    });

    // Arrow down to select second suggestion
    await fireEvent.keyDown(input, { key: 'ArrowDown' });

    const suggestions = container.querySelectorAll('.suggestion');
    expect(suggestions[1]).toHaveClass('selected');
  });

  it('shows validation errors', async () => {
    const AIDesignAssistant = (await import('@psyforge/ai-assistant')).AIDesignAssistant as any;
    AIDesignAssistant.mockImplementationOnce(() => ({
      parseCommand: vi.fn().mockResolvedValue({}),
      generateCode: vi.fn().mockResolvedValue('invalid code'),
      validateCode: vi.fn().mockResolvedValue({
        valid: false,
        errors: ['Missing semicolon', 'Invalid syntax'],
        warnings: []
      })
    }));

    const { getByPlaceholderText, getByText } = render(AICommandPalette, {
      props: { isOpen: true, apiKey: 'test-key' }
    });

    const input = getByPlaceholderText('Describe what you want to add to your experiment...');
    await fireEvent.input(input, { target: { value: 'Add invalid' } });
    await fireEvent.keyDown(input, { key: 'Enter', shiftKey: true });

    await waitFor(() => {
      expect(getByText(/Missing semicolon/)).toBeInTheDocument();
      expect(getByText(/Invalid syntax/)).toBeInTheDocument();
    });
  });

  it('maintains command history', async () => {
    const { getByPlaceholderText, getByText, queryByText } = render(AICommandPalette, {
      props: { isOpen: true, apiKey: 'test-key', experiment: mockExperiment }
    });

    const input = getByPlaceholderText('Describe what you want to add to your experiment...');

    // First command
    await fireEvent.input(input, { target: { value: 'Add trials' } });
    await fireEvent.keyDown(input, { key: 'Enter', shiftKey: true });

    await waitFor(() => {
      expect(getByText('Generated Code Preview')).toBeInTheDocument();
    });

    // Go back
    await fireEvent.click(getByText('Back'));

    // Clear input to see history
    await fireEvent.input(input, { target: { value: '' } });

    await waitFor(() => {
      expect(getByText('Recent Commands')).toBeInTheDocument();
      expect(getByText('Add trials')).toBeInTheDocument();
    });
  });

  it('handles API errors gracefully', async () => {
    const AIDesignAssistant = (await import('@psyforge/ai-assistant')).AIDesignAssistant as any;
    AIDesignAssistant.mockImplementationOnce(() => ({
      parseCommand: vi.fn().mockRejectedValue(new Error('API request failed'))
    }));

    const { getByPlaceholderText, getByText } = render(AICommandPalette, {
      props: { isOpen: true, apiKey: 'test-key' }
    });

    const input = getByPlaceholderText('Describe what you want to add to your experiment...');
    await fireEvent.input(input, { target: { value: 'Add trials' } });
    await fireEvent.keyDown(input, { key: 'Enter', shiftKey: true });

    await waitFor(() => {
      expect(getByText('API request failed')).toBeInTheDocument();
    });
  });
});

