  it('maintains command history', async () => {
    const { getByPlaceholderText, getByText, queryByText } = render(AICommandPalette, {
      props: { isOpen: true, apiKey: 'test-key', experiment: mockExperiment }
    });

    const input = getByPlaceholderText('Describe what you want to add to your experiment...');

    // First command
    await fireEvent.input(input, { target: { value: 'Add trials' } });
    await fireEvent.keyDown(input, { key: 'Enter', shiftKey: true });

    await waitFor(() => {
      expect(getByText('Generated Code Preview')).toBeInTheDocument();
    });

    // Go back
    await fireEvent.click(getByText('Back'));

    // Clear input to see history
    await fireEvent.input(input, { target: { value: '' } });

    await waitFor(() => {
      expect(getByText('Recent Commands')).toBeInTheDocument();
      expect(getByText('Add trials')).toBeInTheDocument();
    });
  });

  it('handles API errors gracefully', async () => {
    const AIDesignAssistant = (await import('@psyforge/ai-assistant')).AIDesignAssistant as any;
    AIDesignAssistant.mockImplementationOnce(() => ({
      parseCommand: vi.fn().mockRejectedValue(new Error('API request failed'))
    }));

    const { getByPlaceholderText, getByText } = render(AICommandPalette, {
      props: { isOpen: true, apiKey: 'test-key' }
    });

    const input = getByPlaceholderText('Describe what you want to add to your experiment...');
    await fireEvent.input(input, { target: { value: 'Add trials' } });
    await fireEvent.keyDown(input, { key: 'Enter', shiftKey: true });

    await waitFor(() => {
      expect(getByText('API request failed')).toBeInTheDocument();
    });
  });
});

