import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, fireEvent, waitFor } from '@testing-library/svelte';
import ExperimentPage from '../src/routes/experiments/+page.svelte';
import { HeadlessRunner, CognitiveModelsFactory } from '@psyforge/headless';
import { AIDesignAssistant } from '@psyforge/ai-assistant';

// Mock modules
vi.mock('@psyforge/headless', () => ({
  HeadlessRunner: vi.fn().mockImplementation(() => ({
    simulate: vi.fn().mockResolvedValue({
      participants: [{
        id: 'p1',
        trials: [
          { rt: 350, response: { key: 'r' }, correct: true },
          { rt: 420, response: { key: 'g' }, correct: false }
        ]
      }],
      totalDuration: 5000,
      memoryUsage: { heapUsedMB: 45, gcCount: 2 }
    }),
    simulateUntil: vi.fn().mockResolvedValue({
      virtualTime: 2500,
      phase: 'main',
      participantState: { trialsCompleted: 5 }
    }),
    getCurrentState: vi.fn().mockReturnValue({
      phase: 'instructions',
      currentEvent: { type: 'text', content: 'Press the key...' },
      virtualTime: 1000,
      participants: [{ id: 'p1', state: 'active' }]
    }),
    getPerformanceMetrics: vi.fn().mockReturnValue({
      fps: 58,
      memoryUsage: { heapUsedMB: 45 },
      cpuUsage: 35,
      simulationSpeed: 1.2,
      frameDrops: 2
    }),
    getVirtualDevice: vi.fn().mockReturnValue({
      latency: 10,
      generateResponse: vi.fn()
    }),
    simulateGazeData: vi.fn().mockReturnValue({
      x: 512, y: 384, pupilSize: 3.2, timestamp: 1000
    }),
    simulateEEGData: vi.fn().mockReturnValue({
      channels: [0.5, -0.3, 0.8],
      timestamp: 1000
    })
  })),
  CognitiveModelsFactory: {
    create: vi.fn().mockReturnValue({
      generateResponse: vi.fn(),
      getParameters: vi.fn().mockReturnValue({ baseRT: 250 })
    })
  }
}));

vi.mock('@psyforge/ai-assistant', () => ({
  AIDesignAssistant: vi.fn().mockImplementation(() => ({
    parseCommand: vi.fn().mockResolvedValue({
      intent: 'add_trial',
      parameters: { type: 'stroop', count: 20 }
    }),
    generateCode: vi.fn().mockResolvedValue(
      `experiment.addTrial({ type: 'stroop', duration: 2000 });`
    ),
    validateCode: vi.fn().mockResolvedValue({ valid: true, errors: [] }),
    getAutocompleteSuggestions: vi.fn().mockResolvedValue([
      'Add 20 Stroop trials',
      'Add practice block'
    ])
  }))
}));

describe('Sprint 5 Integration Tests', () => {
  let component: any;

  beforeEach(() => {
    vi.clearAllMocks();
    // Mock environment
    import.meta.env.VITE_OPENAI_API_KEY = 'test-api-key';
  });

  describe('Time-Travel Simulator Integration', () => {
    it('should toggle simulator and show time-travel controls', async () => {
      const { getByText, getByRole, container } = render(ExperimentPage);

      // Click simulator button
      const simulatorBtn = getByText('Simulator');
      await fireEvent.click(simulatorBtn);

      // Check simulator panel is visible
      await waitFor(() => {
        expect(container.querySelector('.simulator-panel')).toBeInTheDocument();
        expect(getByText('Time-Travel Simulator')).toBeInTheDocument();
      });

      // Check controls are present
      expect(getByRole('button', { name: /play/i })).toBeInTheDocument();
      expect(container.querySelector('input[type="range"]')).toBeInTheDocument();
      expect(getByText(/Speed:/)).toBeInTheDocument();
    });

    it('should run simulation and update preview', async () => {
      const { getByText, container } = render(ExperimentPage);

      // Open simulator
      await fireEvent.click(getByText('Simulator'));

      // Click play button
      const playBtn = container.querySelector('button[title="Play"]');
      await fireEvent.click(playBtn!);

      // Check simulation is running
      await waitFor(() => {
        expect(HeadlessRunner).toHaveBeenCalled();
        const runner = HeadlessRunner.mock.results[0].value;
        expect(runner.simulateUntil).toHaveBeenCalled();
      });

      // Check preview updates
      expect(container.querySelector('.experiment-preview')).toBeInTheDocument();
    });
  });

  describe('Virtual Device Integration', () => {
    it('should initialize virtual devices when enabled', async () => {
      const { getByText, getByLabelText, container } = render(ExperimentPage);

      // Open simulator
      await fireEvent.click(getByText('Simulator'));

      // Enable virtual devices
      const keyboardToggle = getByLabelText('Virtual Keyboard');
      await fireEvent.click(keyboardToggle);

      // Start simulation
      const playBtn = container.querySelector('button[title="Play"]');
      await fireEvent.click(playBtn!);

      await waitFor(() => {
