// This script checks that all Sprint 5 components exist and are properly integrated

const fs = require('fs');
const path = require('path');

console.log('🧪 Sprint 5 Integration Validation\n');

const components = [
  {
    name: 'GUI-009: Time-Travel Scrubber UI',
    files: [
      'packages/gui/src/lib/components/simulator/TimeTravelSimulator.svelte',
      'packages/gui/src/lib/components/simulator/ExperimentPreview.svelte'
    ]
  },
  {
    name: 'SIM-002: Virtual Device Integration',
    files: [
      'packages/headless/src/VirtualDevices.ts',
      'packages/headless/tests/VirtualDeviceIntegration.test.ts'
    ]
  },
  {
    name: 'GUI-010: AI Command Palette',
    files: [
      'packages/gui/src/lib/components/ai/AICommandPalette.svelte',
      'packages/gui/src/lib/components/ai/AICommandPalette.test.ts'
    ]
  },
  {
    name: 'SIM-003: Performance Monitor',
    files: [
      'packages/gui/src/lib/components/simulator/PerformanceMonitor.svelte'
    ]
  },
  {
    name: 'Integration: Experiment Page',
    files: [
      'packages/gui/src/routes/experiments/+page.svelte'
    ]
  }
];

let allPassed = true;

// Check each component
components.forEach(component => {
  console.log(`\n📦 ${component.name}`);

  component.files.forEach(file => {
    const filePath = path.join(__dirname, file);
    const exists = fs.existsSync(filePath);
    const emoji = exists ? '✅' : '❌';
    console.log(`  ${emoji} ${file}`);

    if (!exists) {
      allPassed = false;
    } else {
      // Check file size to ensure it's not empty
      const stats = fs.statSync(filePath);
      if (stats.size < 100) {
        console.log(`     ⚠️  File seems too small (${stats.size} bytes)`);
      }
    }
  });
});

