  console.log(`  ${hasVirtualDevices ? '✅' : '❌'} initializeVirtualDevices method`);
  console.log(`  ${hasGetVirtualDevice ? '✅' : '❌'} getVirtualDevice method`);
  console.log(`  ${hasSimulateGazeData ? '✅' : '❌'} simulateGazeData method`);

  if (!hasVirtualDevices || !hasGetVirtualDevice || !hasSimulateGazeData) {
    allPassed = false;
  }
}

// Check experiment page integration
console.log('\n📦 Experiment Page Integration');
const experimentPagePath = path.join(__dirname, 'packages/gui/src/routes/experiments/+page.svelte');
if (fs.existsSync(experimentPagePath)) {
  const content = fs.readFileSync(experimentPagePath, 'utf8');
  const hasTimeTravelSimulator = content.includes('TimeTravelSimulator');
  const hasAICommandPalette = content.includes('AICommandPalette');
  const hasPerformanceMonitor = content.includes('PerformanceMonitor') || content.includes('performance-monitor');

  console.log(`  ${hasTimeTravelSimulator ? '✅' : '❌'} TimeTravelSimulator import/usage`);
  console.log(`  ${hasAICommandPalette ? '✅' : '❌'} AICommandPalette import/usage`);
  console.log(`  ${hasPerformanceMonitor ? '✅' : '❌'} PerformanceMonitor integration`);

  if (!hasTimeTravelSimulator || !hasAICommandPalette) {
    allPassed = false;
  }
}

// Summary
console.log('\n' + '='.repeat(50));
if (allPassed) {
  console.log('✅ All Sprint 5 components are properly integrated!');
} else {
  console.log('❌ Some components are missing or not properly integrated.');
}
console.log('='.repeat(50));

// Check for performance metrics types
console.log('\n📦 Type Definitions');
const typesPath = path.join(__dirname, 'packages/headless/src/types.ts');
if (fs.existsSync(typesPath)) {
  const content = fs.readFileSync(typesPath, 'utf8');
  const hasPerformanceMetrics = content.includes('PerformanceMetrics');
  const hasSimulationState = content.includes('SimulationState');
  const hasVirtualDeviceConfig = content.includes('VirtualDeviceConfig');

  console.log(`  ${hasPerformanceMetrics ? '✅' : '❌'} PerformanceMetrics interface`);
  console.log(`  ${hasSimulationState ? '✅' : '❌'} SimulationState interface`);
  console.log(`  ${hasVirtualDeviceConfig ? '✅' : '❌'} VirtualDeviceConfig interface`);
}

console.log('\n✨ Sprint 5 Integration Validation Complete');

